"""Reusable shared-player diagram for vector cross-product direction."""
from physics_playground.canvas.player import build_player_document
SCENE=r"""
const scene={draw(ctx,s){const w=s.transform.width,h=s.transform.height,c=s.config.vectorDiagram||{},cx=w/2,cy=h/2;ctx.clearRect(0,0,w,h);ctx.fillStyle='#FAFAFA';ctx.fillRect(0,0,w,h);function arrow(v,color,label,scale){const x=cx+v[0]*scale*s.fraction,y=cy-v[1]*scale*s.fraction;ctx.strokeStyle=color;ctx.fillStyle=color;ctx.lineWidth=5;ctx.beginPath();ctx.moveTo(cx,cy);ctx.lineTo(x,y);ctx.stroke();const a=Math.atan2(y-cy,x-cx);ctx.beginPath();ctx.moveTo(x,y);ctx.lineTo(x-14*Math.cos(a-.5),y-14*Math.sin(a-.5));ctx.lineTo(x-14*Math.cos(a+.5),y-14*Math.sin(a+.5));ctx.fill();ctx.font='bold 15px sans-serif';ctx.fillText(label,x+8,y-8)}arrow(c.motion,'#D55E00',c.motionLabel,105);arrow(c.field,'#0072B2','Magnetic field B',105);ctx.fillStyle=c.forceZ>0?'#2E7D32':(c.forceZ<0?'#7B1FA2':'#555');ctx.font='bold 58px sans-serif';ctx.textAlign='center';ctx.fillText(c.forceZ>0?'⊙':(c.forceZ<0?'⊗':'0'),cx,cy+95);ctx.font='bold 15px sans-serif';ctx.fillText(c.forceLabel,cx,cy+123);}};
"""
def build_vector_direction_document(*,motion:tuple[float,float],field:tuple[float,float],force_z:float,motion_label:str,message:str,seed:int)->str:
    config={"durationMs":1400,"autoplay":False,"seed":seed,"tracks":[{"id":"vector-reveal","label":"Vector direction reveal","x":[0,1]}],"events":[],"completionMessage":message,"vectorDiagram":{"motion":motion,"field":field,"forceZ":force_z,"motionLabel":motion_label,"forceLabel":"Force: out ⊙" if force_z>0 else ("Force: in ⊗" if force_z<0 else "Force: zero")},"view":{"minimum":0,"maximum":1}}
    return build_player_document(config=config,scene_javascript=SCENE,logical_width=720,logical_height=430,accessible_label="Magnetic cross-product vector diagram. "+message,idle_hint="Press Play to reveal the vectors and force direction")
